import { readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const inputPath = resolve(root, "deployment-inputs/deployments.json");
const outputPath = resolve(root, "src/generated/deployments.ts");
const input = JSON.parse(await readFile(inputPath, "utf8"));

const names = Object.keys(input.networks);
const lines = [
  "// Generated by scripts/generate-deployments.mjs. Do not edit manually.",
  'import type { CageCallsNetwork, NetworkName } from "../core/types.js";',
  "",
  `export const UPSTREAM_DEPLOYMENTS = ${JSON.stringify(input.upstream, null, 2)} as const;`,
  "",
  "const presets = {",
];

for (const name of names) {
  const network = input.networks[name];
  const contracts = Object.fromEntries(Object.entries(network.contracts).map(([key, pair]) => [key, pair[0]]));
  const classHashes = Object.fromEntries(Object.entries(network.contracts).map(([key, pair]) => [key, pair[1]]));
  const preset = {
    name: name === "mainnet" ? "Mainnet" : name === "sepolia-dev" ? "Sepolia Dev" : "Sepolia Staging",
    preset: name,
    chainId: network.chainId,
    namespace: "pm",
    deploymentRevision: input.upstream.manifests[name].commit,
    worldAddress: network.worldAddress,
    contracts,
    classHashes,
    toriiUrl: network.toriiUrl,
    cartridgeRpcUrl: network.cartridgeRpcUrl,
    vrfAddress: input.vrfAddress,
    capabilities: network.capabilities,
  };
  lines.push(`  ${JSON.stringify(name)}: ${JSON.stringify(preset, null, 2).replaceAll("\n", "\n  ")},`);
}

lines.push(
  "} satisfies Record<NetworkName, CageCallsNetwork>;",
  "",
  "export const NETWORK_PRESETS = deepFreeze(presets);",
  "export const MAINNET_PRESET = NETWORK_PRESETS.mainnet;",
  'export const SEPOLIA_DEV_PRESET = NETWORK_PRESETS["sepolia-dev"];',
  'export const SEPOLIA_STAGING_PRESET = NETWORK_PRESETS["sepolia-staging"];',
  "",
  "function deepFreeze<T>(value: T): Readonly<T> {",
  '  if (value && typeof value === "object" && !Object.isFrozen(value)) {',
  "    Object.freeze(value);",
  "    for (const child of Object.values(value as Record<string, unknown>)) deepFreeze(child);",
  "  }",
  "  return value;",
  "}",
);

const generated = `${lines.join("\n")}\n`;
if (process.argv.includes("--check")) {
  const current = await readFile(outputPath, "utf8").catch(() => "");
  if (current !== generated) {
    console.error("Generated deployments are stale. Run pnpm generate.");
    process.exitCode = 1;
  }
} else {
  await writeFile(outputPath, generated);
}
